import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = {}

    def add_item(self, item_id, quantity):
        if item_id in self.inventory:
            self.inventory[item_id] += quantity
        else:
            self.inventory[item_id] = quantity

    def remove_item(self, item_id, quantity):
        if item_id in self.inventory and self.inventory[item_id] >= quantity:
            self.inventory[item_id] -= quantity
            if self.inventory[item_id] == 0:
                del self.inventory[item_id]
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.lock = asyncio.Lock()

    async def register(self, websocket):
        async for message in websocket:
            data = json.loads(message)
            if data['action'] == 'register':
                username = data['username']
                player = Player(username)
                self.players[username] = (player, websocket)
                await self.send_inventory(player, websocket)

    async def send_inventory(self, player, websocket):
        await websocket.send(json.dumps({
            'action': 'inventory_update',
            'inventory': player.inventory
        }))

    async def trade_items(self, sender, receiver, item_id, quantity):
        async with self.lock:
            sender_player, sender_ws = self.players[sender]
            receiver_player, receiver_ws = self.players[receiver]

            if sender_player.remove_item(item_id, quantity):
                receiver_player.add_item(item_id, quantity)
                await self.send_inventory(sender_player, sender_ws)
                await self.send_inventory(receiver_player, receiver_ws)
                return True
            return False

    async def handle_connection(self, websocket, path):
        await self.register(websocket)

        try:
            async for message in websocket:
                data = json.loads(message)
                if data['action'] == 'trade':
                    sender = data['sender']
                    receiver = data['receiver']
                    item_id = data['item_id']
                    quantity = data['quantity']
                    success = await self.trade_items(sender, receiver, item_id, quantity)
                    if not success:
                        await websocket.send(json.dumps({'action': 'trade_failed'}))
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            for username, (player, ws) in list(self.players.items()):
                if ws == websocket:
                    del self.players[username]
                    break

async def main():
    server = GameServer()
    async with websockets.serve(server.handle_connection, "localhost", 6789):
        await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())